## Найден файл с хелпером для подписки на `@Observable`

**Путь:** `/Users/mkozin/Developer/radiacode-ios/RadiaCode/Utils/ObservationTracking.swift`

Это расширение на любой `Observable` объект, которое предоставляет три основных метода:

### Содержимое файла:

```swift
import Observation
import Foundation
import Combine

extension Observable where Self: AnyObject {

    // 1. withObservationTracking - базовый трекер изменений
    func withObservationTracking(execute: @Sendable @escaping () -> Void) {
        observableTracking(object: self) {
            execute()
        }
    }

    // 2. publisher для множества свойств (возвращает CurrentValueSubject<Void>)
    func publisher(_ keyPaths: PartialKeyPath<Self>...) -> CurrentValueSubject<Void, Never> {
        let subject = CurrentValueSubject<Void, Never>(())
        observableTracking(object: subject) { [weak self] in
            guard let self else { return }

            for kp in keyPaths {
                _ = self[keyPath: kp]
            }

            subject.send(())
        }

        return subject
    }

    // 3. publisher с типизированным значением
    func publisher<T>(_ keyPah: KeyPath<Self, T>) -> CurrentValueSubject<T, Never> {
        let initValue = self[keyPath: keyPah]
        let subject = CurrentValueSubject<T, Never>(initValue)

        observableTracking(object: subject) { [weak self, weak subject] in
            if let self {
                let value = self[keyPath: keyPah]
                subject?.send(value)
            }
        }

        return subject
    }

    // 4. внутренний observableTracking - рекурсивно отслеживает изменения
    func observableTracking<T>(object: AnyObject?, apply: @escaping () -> T) {
        _ = Observation.withObservationTracking {
            apply()
        } onChange: { [weak object, weak self] in
            guard object != nil else { return }
            DispatchQueue.main.async {
                self?.observableTracking(object: object, apply: apply)
            }
        }
    }
}
```

### Функциональность:

1. **`withObservationTracking`** — выполняет замыкание с отслеживанием изменений свойств
2. **`publisher(_ keyPaths:)`** — создает Combine Publisher для множества свойств
3. **`publisher<T>(_ keyPath:)`** — создает типизированный Publisher для одного свойства, излучающий его значение
4. **`observableTracking`** — внутренний механизм, использующий `Observation.withObservationTracking` с автоматической переподпиской при изменениях

Это правильное место для использования Observation framework (iOS 17+) с Combine для реактивного программирования.
